SELECT DISTINCT js.name
FROM job_seekers js
JOIN applications a ON js.job_seeker_id = a.job_seeker_id;

SELECT DISTINCT js.name
FROM job_seekers js
INNER JOIN applications a ON js.job_seeker_id = a.job_seeker_id;

SELECT job_type_name
FROM job_types
WHERE job_type_id = (SELECT MIN(job_type_id) FROM job_types);
